project:
	4.0.0

		org.springframework.boot
		spring-boot-starter-parent
		{{ boot_version }}


	{{ group_id }}
	{{ artifact_id }}
	0.0.1-SNAPSHOT
	{{ name }}
	{{ description }}














		{{ java_version }}
{%- for key, value in extra_properties %}
		<{{ key }}>{{ value }}</{{ key }}>
{%- endfor %}


{%- for dep in compile_deps %}

			{{ dep.group_id }}
			{{ dep.artifact_id }}
{%- if dep.version %}
			{{ dep.version }}
{%- endif %}

{%- endfor %}
{%- for dep in runtime_deps %}

			{{ dep.group_id }}
			{{ dep.artifact_id }}
{%- if dep.version %}
			{{ dep.version }}
{%- endif %}
			runtime

{%- endfor %}
{%- for dep in annotation_processor_deps %}

			{{ dep.group_id }}
			{{ dep.artifact_id }}
{%- if dep.version %}
			{{ dep.version }}
{%- endif %}
			true

{%- endfor %}
{%- for dep in test_deps %}

			{{ dep.group_id }}
			{{ dep.artifact_id }}
{%- if dep.version %}
			{{ dep.version }}
{%- endif %}
			test

{%- endfor %}

{%- if boms %}



{%- for bom in boms %}

				{{ bom.group_id }}
				{{ bom.artifact_id }}
				{{ bom.version }}
				pom
				import

{%- endfor %}


{%- endif %}




				org.springframework.boot
				spring-boot-maven-plugin



{%- if repositories %}


{%- for repo in repositories %}

			{{ repo.id }}
			{{ repo.name }}
			{{ repo.url }}

				{{ repo.snapshot_enabled }}


{%- endfor %}

{%- endif %}
